    //Expressions 
    function getExpression(expressionName, limbName) {
        var expressions = {
            upperLimbExpression: "var ctrlLayer = thisComp.layer(\"" + limbName + " CTRL\");\n" +
                "var upperLimbLength = ctrlLayer.effect(\"" + limbName + " Limb Control\")(\"Upper Limb Length\").value;\n" +
                "var upperLimbTop = ctrlLayer.effect(\"" + limbName + " Limb Control\")(\"Upper Limb Top Width\").value;\n" +
                "var upperLimbBottom = ctrlLayer.effect(\"" + limbName + " Limb Control\")(\"Upper Limb Bottom Width\").value;\n" +
                "var upperLimbTopCurvature = Math.min(Math.max(ctrlLayer.effect(\"" + limbName + " Limb Control\")(\"Upper Limb Top Curvature\").value, 0), 100) / 100;\n" +
                "var upperLimbBottomCurvature = Math.min(Math.max(ctrlLayer.effect(\"" + limbName + " Limb Control\")(\"Upper Limb Bottom Curvature\").value, 0), 100) / 100;\n" +
                "var ikAngles = ctrlLayer.effect(\"" + limbName + " Limb Control\")(\"IK Angles\");\n" +
                "\n" +
                "// Normalize the curvature to ensure 100% roundness is fully rounded\n" +
                "var topRadius = (upperLimbTop / 1.5523) * upperLimbTopCurvature;\n" +
                "var bottomRadius = (upperLimbBottom / 1.5523) * upperLimbBottomCurvature;\n" +
                "\n" +
                "// Calculate the vertices for the upper rectangle, centered horizontally and positioned vertically\n" +
                "var anchorX = 0;\n" +
                "var anchorY = 0;\n" +
                "\n" +
                "// Rotation of the upper limb (reading degrees and converting to radians)\n" +
                "var rotation = ikAngles[0];\n" +
                "\n" +
                "// Rotate function\n" +
                "function rotate(point, angle) {\n" +
                "    var rad = degreesToRadians(angle);\n" +
                "    var x = point[0] * Math.cos(rad) - point[1] * Math.sin(rad);\n" +
                "    var y = point[0] * Math.sin(rad) + point[1] * Math.cos(rad);\n" +
                "    return [x, y];\n" +
                "}\n" +
                "\n" +
                "// Calculate rotated positions\n" +
                "var upperLimb = [\n" +
                "    rotate([anchorX - upperLimbTop / 2, anchorY], rotation), // Top-left\n" +
                "    rotate([anchorX + upperLimbTop / 2, anchorY], rotation), // Top-right\n" +
                "    rotate([anchorX + upperLimbBottom / 2, anchorY + upperLimbLength], rotation), // Bottom-right\n" +
                "    rotate([anchorX - upperLimbBottom / 2, anchorY + upperLimbLength], rotation) // Bottom-left\n" +
                "];\n" +
                "\n" +
                "// Adjust the tangents\n" +
                "var inTangents = [\n" +
                "    rotate([0, 0], rotation), // Top-left\n" +
                "    rotate([0, -topRadius], rotation), // Top-right\n" +
                "    rotate([0, 0], rotation), // Bottom-right\n" +
                "    rotate([0, bottomRadius], rotation) // Bottom-left\n" +
                "];\n" +
                "\n" +
                "var outTangents = [\n" +
                "    rotate([0, -topRadius], rotation), // Top-left\n" +
                "    rotate([0, 0], rotation), // Top-right\n" +
                "    rotate([0, bottomRadius], rotation), // Bottom-right\n" +
                "    rotate([0, 0], rotation) // Bottom-left\n" +
                "];\n" +
                "\n" +
                "// Create the path\n" +
                "createPath(upperLimb, inTangents, outTangents, true);",
            lowerLimbExpression: "var ctrlLayer = thisComp.layer(\"" + limbName + " CTRL\");\n" +
                "var upperLimbLength = ctrlLayer.effect(\"" + limbName + " Limb Control\")(\"Upper Limb Length\").value;\n" +
                "var lowerLimbLength = ctrlLayer.effect(\"" + limbName + " Limb Control\")(\"Lower Limb Length\").value;\n" +
                "var lowerLimbTop = ctrlLayer.effect(\"" + limbName + " Limb Control\")(\"Lower Limb Top Width\").value;\n" +
                "var lowerLimbBottom = ctrlLayer.effect(\"" + limbName + " Limb Control\")(\"Lower Limb Bottom Width\").value;\n" +
                "var lowerLimbTopCurvature = Math.min(Math.max(ctrlLayer.effect(\"" + limbName + " Limb Control\")(\"Lower Limb Top Curvature\").value, 0), 100) / 100;\n" +
                "var lowerLimbBottomCurvature = Math.min(Math.max(ctrlLayer.effect(\"" + limbName + " Limb Control\")(\"Lower Limb Bottom Curvature\").value, 0), 100) / 100;\n" +
                "var ikAngles = ctrlLayer.effect(\"" + limbName + " Limb Control\")(\"IK Angles\");\n" +
                "\n" +
                "// Normalize the curvature to ensure 100% roundness is fully rounded\n" +
                "var topRadius = (lowerLimbTop / 1.5523) * lowerLimbTopCurvature;\n" +
                "var bottomRadius = (lowerLimbBottom / 1.5523) * lowerLimbBottomCurvature;\n" +
                "\n" +
                "// Rotation of the upper and lower limbs\n" +
                "// Read angles in degrees and convert to radians\n" +
                "var upperLimbRotation = degreesToRadians(ikAngles[0]);\n" +
                "var lowerLimbRotation = degreesToRadians(ikAngles[1]);\n" +
                "\n" +
                "// Rotate function\n" +
                "function rotate(point, angle, origin) {\n" +
                "    var rad = angle;\n" +
                "    var x = origin[0] + (point[0] - origin[0]) * Math.cos(rad) - (point[1] - origin[1]) * Math.sin(rad);\n" +
                "    var y = origin[1] + (point[0] - origin[0]) * Math.sin(rad) + (point[1] - origin[1]) * Math.cos(rad);\n" +
                "    return [x, y];\n" +
                "}\n" +
                "\n" +
                "// Calculate the endpoint of the upper limb\n" +
                "var upperLimbEndpoint = rotate([0, upperLimbLength], upperLimbRotation, [0, 0]);\n" +
                "\n" +
                "// Set the anchor point for the lower limb at the endpoint of the upper limb\n" +
                "var anchorX = upperLimbEndpoint[0];\n" +
                "var anchorY = upperLimbEndpoint[1];\n" +
                "\n" +
                "// Calculate the vector and distance from the upper limb endpoint to the CTRL position\n" +
                "var ctrlPos = ctrlLayer.position;\n" +
                "var vector = ctrlPos - [anchorX, anchorY];\n" +
                "var distance = length(vector);\n" +
                "\n" +
                "// Clamp the distance to ensure it's within the reach of the upper and lower limbs\n" +
                "var minDistance = Math.max(upperLimbLength - lowerLimbLength, 0);\n" +
                "var maxDistance = upperLimbLength + lowerLimbLength;\n" +
                "distance = Math.max(minDistance, Math.min(distance, maxDistance));\n" +
                "\n" +
                "// Adjust the lower limb length based on the clamped distance\n" +
                "var adjustedLowerLimbLength = Math.max(0, distance - upperLimbLength);\n" +
                "\n" +
                "// Calculate rotated positions for the lower limb, ensuring they move with the upper limb's endpoint\n" +
                "var lowerLimb = [\n" +
                "    rotate([-lowerLimbTop / 2, 0], lowerLimbRotation, [0, 0]), // Top-left\n" +
                "    rotate([lowerLimbTop / 2, 0], lowerLimbRotation, [0, 0]), // Top-right\n" +
                "    rotate([lowerLimbBottom / 2, adjustedLowerLimbLength], lowerLimbRotation, [0, 0]), // Bottom-right\n" +
                "    rotate([-lowerLimbBottom / 2, adjustedLowerLimbLength], lowerLimbRotation, [0, 0]) // Bottom-left\n" +
                "];\n" +
                "\n" +
                "// Translate the lower limb positions to the anchor point\n" +
                "lowerLimb = lowerLimb.map(function(point) {\n" +
                "    return [point[0] + anchorX, point[1] + anchorY];\n" +
                "});\n" +
                "\n" +
                "// Adjust the tangents\n" +
                "var inTangents = [\n" +
                "    [0, 0], // Top-left\n" +
                "    rotate([0, -topRadius], lowerLimbRotation, [0, 0]), // Top-right\n" +
                "    [0, 0], // Bottom-right\n" +
                "    rotate([0, bottomRadius], lowerLimbRotation, [0, 0]) // Bottom-left\n" +
                "];\n" +
                "\n" +
                "var outTangents = [\n" +
                "    rotate([0, -topRadius], lowerLimbRotation, [0, 0]), // Top-left\n" +
                "    [0, 0], // Top-right\n" +
                "    rotate([0, bottomRadius], lowerLimbRotation, [0, 0]), // Bottom-right\n" +
                "    [0, 0] // Bottom-left\n" +
                "];\n" +
                "\n" +
                "// Create the path\n" +
                "createPath(lowerLimb, inTangents, outTangents, true);",
            armFillColorExpression: "thisComp.layer('" + limbName + " CTRL').effect('" + limbName + " Limb Control')('Arm Fill Color')",
            armFillOpacityExpression: "thisComp.layer('" + limbName + " CTRL').effect('" + limbName + " Limb Control')('Arm Fill Opacity')",
            armStrokeColorExpression: "thisComp.layer('" + limbName + " CTRL').effect('" + limbName + " Limb Control')('Arm Stroke Color')",
            armStrokeWidthExpression: "thisComp.layer('" + limbName + " CTRL').effect('" + limbName + " Limb Control')('Arm Stroke Width')",
            ikAnglesExpression: "var ctrlLayer = thisComp.layer('" + limbName + " CTRL');\n" +
                "var upperLimbLength = ctrlLayer.effect('" + limbName + " Limb Control')('Upper Limb Length').value;\n" +
                "var lowerLimbLength = ctrlLayer.effect('" + limbName + " Limb Control')('Lower Limb Length').value;\n" +
                "var disableIK = ctrlLayer.effect('" + limbName + " Limb Control')('Disable IK').value;\n" +
                "var upperLimbAngle = ctrlLayer.effect('" + limbName + " Limb Control')('Upper Limb Angle').value;\n" +
                "var lowerLimbAngle = ctrlLayer.effect('" + limbName + " Limb Control')('Lower Limb Angle').value;\n" +
                "if (disableIK == 1) {\n" +
                "    var ikAngles = [upperLimbAngle, lowerLimbAngle];\n" +
                "} else {\n" +
                "    var goal = ctrlLayer;\n" +
                "    var flip = ctrlLayer.effect('" + limbName + " Limb Control')('Flip IK').value;\n" +
                "    // Function to calculate world position\n" +
                "    function worldPos(layer) {\n" +
                "        return layer.toWorld(layer.anchorPoint);\n" +
                "    }\n" +
                "    // Function to calculate rotation angle between two points\n" +
                "    function rotationFunction(pointA, pointB) {\n" +
                "        var diff = pointB - pointA;\n" +
                "        return Math.atan2(diff[1], diff[0]);\n" +
                "    }\n" +
                "    // Get the initial positions\n" +
                "    var upperLimbInitialPos = thisComp.layer('" + limbName + "').position; // A\n" +
                "    var lowerLimbInitialPos = upperLimbInitialPos + [0, upperLimbLength]; // B\n" +
                "    var goalPos = goal.toWorld(goal.anchorPoint); // C\n" +
                "    // Calculate the distances\n" +
                "    var upperToLowerDist = upperLimbLength; // Distance from upper limb to lower limb\n" +
                "    var lowerToGoalDist = lowerLimbLength; // Distance from lower limb to goal\n" +
                "    var upperToGoalDist = length(goalPos - upperLimbInitialPos); // Distance from upper limb to goal\n" +
                "    // Law of Cosines\n" +
                "    var LofC = (upperToLowerDist * upperToLowerDist - lowerToGoalDist * lowerToGoalDist + upperToGoalDist * upperToGoalDist) / (2 * upperToGoalDist);\n" +
                "    var midPointIK = upperToGoalDist - LofC;\n" +
                "    var angleB = Math.acos(Math.max(-1, Math.min(1, midPointIK / lowerToGoalDist))); // Angle B in radians\n" +
                "    var angleA = Math.acos(Math.max(-1, Math.min(1, LofC / upperToLowerDist))); // Angle A in radians\n" +
                "    // Calculate rotations\n" +
                "    var lowerLimbRotationAngle;\n" +
                "    if (flip == 1) {\n" +
                "        lowerLimbRotationAngle = angleB + angleA;\n" +
                "    } else {\n" +
                "        lowerLimbRotationAngle = -(angleB + angleA);\n" +
                "    }\n" +
                "    var upperLimbRotationAngle;\n" +
                "    if (flip == 1) {\n" +
                "        upperLimbRotationAngle = -angleA;\n" +
                "    } else {\n" +
                "        upperLimbRotationAngle = angleA;\n" +
                "    }\n" +
                "    var uLimbToIKLineAngle = rotationFunction(upperLimbInitialPos, goalPos); // Angle between Upper Limb and IK Line\n" +
                "    // Calculate the final rotation angles\n" +
                "    var upperLimbRotation = radiansToDegrees(uLimbToIKLineAngle) + radiansToDegrees(upperLimbRotationAngle) - 90;\n" +
                "    var lowerLimbRotation = radiansToDegrees(lowerLimbRotationAngle) + upperLimbRotation;\n" +
                "    // Output the angles in radians\n" +
                "    var ikAngles = [upperLimbRotation, lowerLimbRotation];\n" +
                "}\n" +
                "ikAngles;",
            upperLimbStrokePathExpression: "content('Upper Limb').content('Path 1').path",
            lowerLimbStrokePathExpression: "content('Lower Limb').content('Path 1').path",
            elbowCompExpression: "var upperLimbLength = thisComp.layer('" + limbName + " CTRL').effect('" + limbName + " Limb Control')('Upper Limb Length').value;\n" +
                "var ikAngles = thisComp.layer('" + limbName + " CTRL').effect('" + limbName + " Limb Control')('IK Angles').value;\n" +
                "var upperLimbRotation = degreesToRadians(ikAngles[0]);\n" +
                "\n" +
                "var startPos = thisComp.layer('" + limbName + "').toComp(thisComp.layer('" + limbName + "').anchorPoint);\n" +
                "\n" +
                "// Calculate the elbow position relative to the start position\n" +
                "var elbowPos = [\n" +
                "    startPos[0] + upperLimbLength * Math.sin(-upperLimbRotation),\n" +
                "    startPos[1] + upperLimbLength * Math.cos(-upperLimbRotation)\n" +
                "];\n" +
                "\n" +
                "// Output the elbow position in comp space\n" +
                "elbowPos;",
            elbowLayerExpression: "var upperLimbLength = thisComp.layer('" + limbName + " CTRL').effect('" + limbName + " Limb Control')('Upper Limb Length').value;\n" +
                "var ikAngles = thisComp.layer('" + limbName + " CTRL').effect('" + limbName + " Limb Control')('IK Angles').value;\n" +
                "var upperLimbRotation = degreesToRadians(ikAngles[0]);\n" +
                "\n" +
                "// Calculate the elbow position in layer space\n" +
                "var elbowPosLayerSpace = [\n" +
                "    upperLimbLength * Math.sin(-upperLimbRotation),\n" +
                "    upperLimbLength * Math.cos(-upperLimbRotation)\n" +
                "];\n" +
                "\n" +
                "// Output the elbow position in layer space\n" +
                "elbowPosLayerSpace;",
            wristCompExpression: "var limbLayer = thisComp.layer('" + limbName + "');\n" +
                "var ctrlLayer = thisComp.layer('" + limbName + " CTRL');\n" +
                "\n" +
                "var upperLimbLength = ctrlLayer.effect('" + limbName + " Limb Control')('Upper Limb Length').value;\n" +
                "var lowerLimbLength = ctrlLayer.effect('" + limbName + " Limb Control')('Lower Limb Length').value;\n" +
                "var ikAngles = ctrlLayer.effect('" + limbName + " Limb Control')('IK Angles').value;\n" +
                "var upperLimbRotation = degreesToRadians(ikAngles[0]);\n" +
                "var lowerLimbRotation = degreesToRadians(ikAngles[1]);\n" +
                "\n" +
                "// Calculate the elbow position in layer space\n" +
                "var elbowPosLayerSpace = [\n" +
                "    upperLimbLength * Math.sin(-upperLimbRotation),\n" +
                "    upperLimbLength * Math.cos(-upperLimbRotation)\n" +
                "];\n" +
                "\n" +
                "// Calculate the wrist position in layer space\n" +
                "var wristPosLayerSpace = [\n" +
                "    elbowPosLayerSpace[0] + lowerLimbLength * Math.sin(-lowerLimbRotation),\n" +
                "    elbowPosLayerSpace[1] + lowerLimbLength * Math.cos(-lowerLimbRotation)\n" +
                "];\n" +
                "\n" +
                "// Convert the wrist position from limb layer space to comp space\n" +
                "var wristPosCompSpace = limbLayer.toComp(wristPosLayerSpace);\n" +
                "\n" +
                "// Output the adjusted wrist position in comp space\n" +
                "[wristPosCompSpace[0], wristPosCompSpace[1]];",
            wristLayerExpression: "var upperLimbLength = thisComp.layer('" + limbName + " CTRL').effect('" + limbName + " Limb Control')('Upper Limb Length').value;\n" +
                "var lowerLimbLength = thisComp.layer('" + limbName + " CTRL').effect('" + limbName + " Limb Control')('Lower Limb Length').value;\n" +
                "var ikAngles = thisComp.layer('" + limbName + " CTRL').effect('" + limbName + " Limb Control')('IK Angles').value;\n" +
                "var upperLimbRotation = degreesToRadians(ikAngles[0]);\n" +
                "var lowerLimbRotation = degreesToRadians(ikAngles[1]);\n" +
                "\n" +
                "// Calculate the elbow position in layer space\n" +
                "var elbowPosLayerSpace = [\n" +
                "    upperLimbLength * Math.sin(-upperLimbRotation),\n" +
                "    upperLimbLength * Math.cos(-upperLimbRotation)\n" +
                "];\n" +
                "\n" +
                "// Calculate the wrist position in layer space\n" +
                "var wristPosLayerSpace = [\n" +
                "    elbowPosLayerSpace[0] + lowerLimbLength * Math.sin(-lowerLimbRotation),\n" +
                "    elbowPosLayerSpace[1] + lowerLimbLength * Math.cos(-lowerLimbRotation)\n" +
                "];\n" +
                "\n" +
                "// Output the wrist position in layer space\n" +
                "wristPosLayerSpace;"    
        
        };
        return expressions[expressionName];
    }
    


